sp_widget.client_script:
api.controller = function ($scope, $location, $rootScope,spModal,$uibModal, spUtil, amb, $timeout) {
	//------------------------------------------------------------------------------------------------------------------------
	// COMPANY: DISCOVER TECHNOLOGIES
	// CUSTOMIZED BY: KARINA TORRES
	// RECURSIVE GRAPHICAL TREE FOR PROCESS TEMPLATE
	// HELPUL LINKS: https://gojs.net/latest/intro/textblocks.html
	//------------------------------------------------------------------------------------------------------------------------

	// TECH - Update - main, constants, variables
	// Global constants and variables	
	var c = this;
	var TREE_CONST;
	var modalObjects;
	var $go;
	var diagram;
	var myOverview;
	var treeOrientation;
	var treeNodeAngle;
	var url_id;
	var watcher;

	// call main function
	main();

	function main(){
		TREE_CONST = loadTreeConstants();
		modalObjects = loadModalObjects();
		$go = go.GraphObject.make;  // for conciseness in defining templates
		// 2.8 | 2022-03-04 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel; avatar popover
		c.data.isPopoverOpened = false;

		// 2.8 | 2022-03-10 | mmcc | STRY0114672 - Org Hierarchy Full Screen- Tree Node- Any Members List- Update to Popover Panel
		c.data.isPopoverListOpened = false;

		c.data.topIconOpacity = c.data.settings.isFullScreen? TREE_CONST.icon_opacity_normal :0.0;
		c.data.showIcons = false;
		c.data.topOU="";

		// set default tree orientation based on system setting (this will change when user perference is enabled)
		if(!c.data.settings.isSystemTreeOrientationVertical){
			treeOrientation = "Horizontal";
			treeNodeAngle = 0;
		} else {
			treeOrientation = "Vertical";
			treeNodeAngle = 90;
		}
		// STRY0074597
		setOUPicker();
		if (!c.data.selectedId && c.data.currentTopOU){
			c.data.selectedId = c.data.currentTopOU;
		}
		// STRY0069986 - move to top
		url_id = $location.search().sys_id;
		if(!url_id){
			broadcastTopNodeChange(c.data.selectedId);
		}
		// STRY0116812
		initRecordWatcher("x_153465_discovert_discover_office_hierarchy", "u_top_ou=" + c.data.currentTopOU);

		$scope.topOU={
			displayValue: c.data.office_name,
			value: c.data.currentTopOU,
			name: 'topOU'
		};
		$scope.page = {
			displayValue: $scope.data.title,
			value: $scope.data.selectedId,
			name: 'page'
		};
		if ($scope.data.selectedId) {
			// STRY0116823
			resetDiagram();
		}

		// DFCT0010275
		if($scope.data.map.length > 0){	
			// this event handler is called when the diagram is first ready
			diagram.addDiagramListener("InitialLayoutCompleted", function(e) {
				var node = diagram.findNodeForKey(c.data.selectedId);
				// and center it and select it
				// STRY0072032
				diagram.centerRect(node.actualBounds);
			});
		}		

	}

	function loadTreeConstants(){	
		var oTREE_CONST = {
			//var font = "13px Helvetica, Arial, sans-serif";
			fontStyle: "14px Segoe UI",
			node_id: "page_map",
			minHeight: 12,
			// STRY0096158 - ORG - Template Tree Min Size to avoid cutting off tool tip
			diagramMinHeight: 150,

			outlineWidth: 2,
			topPicCornerOffset: 12,
			leftPicCornerOffset: 12,
			leftIconCornerOffset: 8,
			bottomIconCornerOffset: -3,
			rightIconCornerOffset: -8,
			profilePicSize: 32,
			profilePicCircleSize: 34,
			iconCircleSize: 26,

			// 2.5.21 | 09.08.2020 | KT | UI  | STRY0074067: TECH - Tasker - Unified CSS on widgets (Internal Story, PO story needed)
			// TREE SPECIFIC CONSTANTS
			// these can change per tree (Org, Task, Template)
			node_active_bg: '#33738e',
			node_inactive_bg: '#787878',
			node_selected_border: '#FFD247',

			// STRY0108231 - NOTE these are NOT used in Organizational Hiearchy with SVG icons
			icon_normal_stroke: "white",
			icon_hover_stroke: "#F00",
			icon_warning_stroke: "#FF0",
			toolTipBackgroundColor: '#FFFFFF', // "#C5C5C5"
			tooltipTextColor: '#3A3F51',

			// settings for the list widgets use these objects
			icon_opacity_normal: 1.00,
			icon_opacity_hover: 0.75,
			use_user_image: 'USE_USER_IMAGE'

		};
		return oTREE_CONST;
	}

	function loadModalObjects(){
		var oModalObjects = {
			informationForm: {
				modalType: "form",
				title: '', // needs data to set
				table: 'x_153465_discovert_discover_office_hierarchy',
				sys_id: '',  // needs key added inline
				view: 'Default View'
			},
			subOUList: {
				modalType: "list",
				title: '', // needs data to set
				o: 'level_order,office_name',
				d: 'asc',
				table: 'x_153465_discovert_discover_office_hierarchy',
				filter: 'parent=',  // needs key added inline
				view: 'Default View'
			},
			membersOUList: {
				modalType: "list",
				title: '', // needs data to set
				o: 'office_member',
				d: 'asc',
				table: 'x_153465_discovert_discover_office_members',
				filter: 'discover_office_hierarchy=',  // needs key added inline
				view: 'sp'
			},
			contactsOUList: {
				modalType: "list",
				title: '', // needs data to set
				o: 'u_tasker_contact',
				d: 'asc',
				table: 'x_153465_discovert_organizational_contacts',
				filter: 'u_contact_ou=',  // needs key added inline
				view: 'Default View'		
			},
			OUReport: {
				modalType: "report",
				title: '', // needs data to set
				o: 'title',
				d: 'asc',
				table: 'sys_report',
				filter: 'primary_assignee=',  // needs key added inline
				view: 'Default View'
			},
			relatedTaskOUList: {
				modalType: "list",
				title: '', // needs data to set
				o: 'number',
				d: 'desc',
				table: 'x_153465_discovert_route_task_instance',
				filter: '	primary_assignee=',  // needs key added inline
				view: 'Default View'
			},
			requestChangeForm: {
				modalType: "form",
				title: '', // needs data to set
				table: 'x_153465_discovert_tasker_requests',
				sys_id: -1,
				u_ou_parent: '', // needs key added inline
				view: 'ou_requesttop'
			},
			createNewForm: {
				modalType: "form",
				title: '', // needs data to set
				table: 'x_153465_discovert_discover_office_hierarchy',
				sys_id: -1,
				query: '', // needs key added inline
				view: 'Simple'
			}
		};
		return oModalObjects;
	}

	$scope.$on("$destroy", function (event) {
		$timeout.cancel(c.popoverTimeout);
		$timeout.cancel(c.popoverListTimeout);
	});

	$(window).on("resize", function() {
		// not sure why, but increasing the minHeight seems to work, but not sure why
		TREE_CONST.minHeight = 12;
		resizeDiagram();
	});

	// add selected ou to favorites
	$scope.addToFavorites = function() {
		var selectedNode = diagram.findNodeForKey(c.data.selectedId);
		diagram.commandHandler.resetZoom($scope.data.settings.selectPercent/100);
		diagram.centerRect(selectedNode.actualBounds);			

		$scope.data.favoriteChanged = true; 
		$scope.data.settings.favorite = {
			value: c.data.selectedId,
			topId: c.data.currentTopOU};
		spUtil.update($scope).then(function() {
			// submit favorite change back to server
			return;
		});
	};

	// Zoom to Favorite
	$scope.zoomToFavorite = function() {
// TODO - post back change if top ou of favorite is not current top ou
		if(c.data.settings.favorite.value && c.data.settings.favorite.value != c.data.selectedId){
			c.data.selectedId = c.data.settings.favorite.value;
			var favoriteOUNode = diagram.findNodeForKey(c.data.settings.favorite.value);
			if(favoriteOUNode){
				diagram.select(favoriteOUNode);
			} else {
// TODO - determine if we want a message here 
// 				Or if we want me to load a different tree, 
// 				or, if we wnat to prompt to load a differnt tree
alert('Temporary Message - favorite OU not in current diagram');				
			}
		}

	};

	// Zoom to Default OU
	$scope.zoomToDefaultOU = function() {
		if(c.data.settings.defaultOU.value && c.data.settings.defaultOU.value != c.data.selectedId){
			c.data.selectedId = c.data.settings.defaultOU.value;
			var defaultOUNode = diagram.findNodeForKey(c.data.settings.defaultOU.value);
			if(defaultOUNode){
				diagram.select(defaultOUNode);
			} else {
// TODO - determine if we want a message here 
// 				Or if we want me to load a different tree, 
// 				or, if we wnat to prompt to load a differnt tree
alert('Temporary Message - default OU not in current diagram');				
			}
		}
	};

	// Zoom to Top OU
	$scope.zoomToTopOU = function() {
		if(c.data.currentTopOU && c.data.currentTopOU != c.data.selectedId){
			c.data.selectedId = c.data.currentTopOU;
			var topOUNode = diagram.findNodeForKey(c.data.currentTopOU);
			if(topOUNode){
				diagram.select(topOUNode);
			}
		}
	};

	// Zoom to Selected
	$scope.zoomToSelected = function() {
		var selectedNode = diagram.findNodeForKey(c.data.selectedId);
		diagram.commandHandler.resetZoom(1.0);
		$scope.data.settings.selectPercent='100';
		diagram.centerRect(selectedNode.actualBounds);
	};

	// Zoom to full tree
	$scope.zoomToFullTree = function() {
		$scope.data.settings.selectPercent="tree";
		diagram.zoomToRect(diagram.documentBounds);
	};

	// Zoom to Selected
	$scope.zoomToPercent = function() {
		if($scope.data.settings.selectPercent=="tree"){
			this.zoomToFullTree();
		} else {
			var selectedNode = diagram.findNodeForKey(c.data.selectedId);
			diagram.commandHandler.resetZoom($scope.data.settings.selectPercent/100);
			diagram.centerRect(selectedNode.actualBounds);			
		}

		$scope.data.percentChanged = true; 
		spUtil.update($scope).then(function() {
			// submit percent change back to server
			return;
		});

	};

	// RJA 2021.04.14 - TUP - Filter was not working for OU Templates in Template LIst screen - issue introduced in 2.6
	function initRecordWatcher(table, filter) {
		if (watcher)
			watcher.unsubscribe();

		if (table && filter) {
			// STRY0093948 - when a row is removed, broadcast event to Tab Form with Tabs to update the count
			var params = {};
			var watcherChannel = amb.getChannelRW(table, filter);
			amb.connect();
			watcher = watcherChannel.subscribe(function(name) {
				var changes = name.data.changes;
				var sys_id = name.data.sys_id;
				switch (name.data.operation) {
					case "update":
						var nodeChangedFound = diagram.model.findNodeDataForKey(sys_id);
						if (nodeChangedFound) {
							var nodeDataChanged = false;
							for (var change in changes) {
								if (c.data.fieldsInModel[changes[change]]) {
									nodeDataChanged = true;
									break;
								}
							}
							if (nodeDataChanged) {
								updateModelNodeData(nodeChangedFound, name.data.record);
							}
						}
						break;
					case "insert":
						if (name.data.record.parent) {
							var newNodeData = createModelNodeData(sys_id, name.data.record);
							diagram.startTransaction("Add new Organizational Unit");
							diagram.model.addNodeData(newNodeData);
							diagram.model.setParentKeyForNodeData(newNodeData, name.data.record.parent.value);
							diagram.commitTransaction("Add new Organizational Unit");
						}
						break;
					case "delete":
						var nodeDeletedFound = diagram.model.findNodeDataForKey(sys_id);
						if (nodeDeletedFound) {
							diagram.model.removeNodeData(nodeDeletedFound);
						}
				}
			});
		}
	}

	function createModelNodeData(sys_id, record) {
		var newNodeData = {};
		newNodeData.key = sys_id;
		newNodeData.sys_id = sys_id;
		for (var key in record) {
			var displayValue = '';
			var fieldLabel = '';
			var field = c.data.fieldsInModel[key];
			if (field) {
				fieldLabel = field.fieldLabel;

				// 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode
				// displayValue = record[key].display_value;
				if ((field.fieldName == 'u_signature_instructions') || (field.fieldName == 'instructions')) {
					displayValue = htmlToStringService.convertHtmlToString(record[key].display_value);
				} else {
					displayValue = record[key].display_value;
				}

				if (field.maxChars > 0)
					displayValue = displayValue.toString().length > field.maxChars ? displayValue.substring(0, field.maxChars - 1) : displayValue.toString();
				if (field.hasValue) {
					// many have value, only a few have only value 'calchaschildren', 'parent', 'u_wait_for_subtasks_to_finish'
					// others 'primary_assignee', 'primary_office', 'tasking_authority', 'state', 'assigned_to_individual'
					newNodeData[key] = record[key].value;
				}
				if (field.keyUsesDisplayOnly) {
					// 'status', 'task_name', 'u_active_subtasks', 'order', 'u_reviewer': 
					newNodeData[key] = displayValue;
				}
				if (field.hasDiplayValue) {
					// 'state_DisplayValue', 'assigned_to_individual_DisplayValue'
					newNodeData[key + '_DisplayValue'] = displayValue;
				}
				if (field.type == 'date') {
					var date_number = getDateFromFormat(record[key].value, g_user_date_time_format);
					// STRY0091251 - STRETCH-TUP(Estimated Duration Calculation)  - calculate Estimated Duration for Task Template Tree to show where Parent duration is shorter than sum of children
					// server is loading duration values in UTC
					var gdt = new Date();
					// returns the offset in minutes
					// updates offset to miliseconds
					date_number = date_number - (gdt.getTimezoneOffset() * 60 * 1000);
					newNodeData[key] = date_number;
				}
				if (field.type=='time') {
					var gdTime = new Date(record[key].value);
					var time_number = (gdTime.getHours() * 60 + gdTime.getMinutes() * 60 + gdTime.getSeconds()) * 1000;
				}
				if (field.type=='boolean') {
					newNodeData[key] = (record[key].value == "true" || record[key].value == true);
				}
				//  STRY0113883
				if (field.type == 'photo' || field.type == 'profile') {
						// these are handled in a function b/c they need to post back to the server
						loadUserInfo(field.type, newNodeData.key, key, record[key].value, displayValue );
				}
				if (field.type == 'list') {
					var list_value = record[key] == null || record[key] == undefined ? '': record[key];
					newNodeData[key] = list_value;

					// load the list into the Map
					newNodeData[key + '_list'] = [];
					var listArray = displayValue.split(',');
					for(var i=0; i<listArray.length; i++){
						var arrayItem = {};
						arrayItem.displayName = listArray[i];
						if(arrayItem.displayName != null && arrayItem.displayName != undefined && arrayItem.displayName != ''){
							newNodeData[key + '_list'].push(arrayItem);
						}
					}
				}

			} //if field wasn't found do nothing
		}
		newNodeData.name = newNodeData.office_name + '\n  (' + newNodeData.office_abbreviation + ')';
		var ouHAValue = record.u_ou_hierarchy_administrators;
		newNodeData.isAdmin = (c.data.isGHA || (ouHAValue && ouHAValue.indexOf(c.data.currentUser)>=0));

		return newNodeData;
	}
	// load all of the field names used in the office tree nodes
	function updateModelNodeData(nodeData, record) {
		for (var key in record) {
			var displayValue = '';
			var fieldLabel = '';
			var field = c.data.fieldsInModel[key];
			if (field) {
				fieldLabel = field.fieldLabel;

				// 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode
				// displayValue = record[key].display_value;
				if ((field.fieldName == 'u_signature_instructions') || (field.fieldName == 'instructions')) {
					displayValue = htmlToStringService.convertHtmlToString(record[key].display_value);
				} else {
					displayValue = record[key].display_value;
				}

				if (field.maxChars > 0)
					displayValue = displayValue.toString().length > field.maxChars ? displayValue.substring(0, field.maxChars - 1) : displayValue.toString();
				if (field.hasValue) {
					// many have value, only a few have only value 'calchaschildren', 'parent', 'u_wait_for_subtasks_to_finish'
					// others 'primary_assignee', 'primary_office', 'tasking_authority', 'state', 'assigned_to_individual'
					diagram.model.setDataProperty(nodeData, key, record[key].value); // this is the default value to key match
				}
				if (field.keyUsesDisplayOnly) {
					// 'status', 'task_name', 'u_active_subtasks', 'order', 'u_reviewer': 
					diagram.model.setDataProperty(nodeData, key, displayValue);
				}
				if (field.hasDiplayValue) {
					// 'state_DisplayValue', 'assigned_to_individual_DisplayValue'
					diagram.model.setDataProperty(nodeData, key + '_DisplayValue', displayValue);
				}
				switch (field.type){
					case 'date':
						var date_number = getDateFromFormat(record[key].value, g_user_date_time_format);
						// STRY0091251 - STRETCH-TUP(Estimated Duration Calculation)  - calculate Estimated Duration for Task Template Tree to show where Parent duration is shorter than sum of children
						// server is loading duration values in UTC
						var gdt = new Date();
						// returns the offset in minutes
						// updates offset to miliseconds
						date_number = date_number - (gdt.getTimezoneOffset() * 60 * 1000);
						diagram.model.setDataProperty(nodeData, key, date_number);
						break;
					case 'time':
						var gdTime = new Date(record[key].value);
						var time_number = (gdTime.getHours() * 60 + gdTime.getMinutes() * 60 + gdTime.getSeconds()) * 1000;
						diagram.model.setDataProperty(nodeData, key, time_number);
						break;
					case 'boolean':
						var bValue = (record[key].value == "true" || record[key].value == true);
						diagram.model.setDataProperty(nodeData, key, bValue);
						nodeData[key] = (record[key].value == "true" || record[key].value == true);
						break;
					case 'list':
						var list_value = record[key] == null || record[key] == undefined ? '': record[key];
						nodeData[key] = list_value;

						// load the list into the Map
						nodeData[key + '_list'] = [];
						var listArray = displayValue.split(',');
						for(var i=0; i<listArray.length; i++){
							var arrayItem = {};
							arrayItem.displayName = listArray[i];
							if(arrayItem.displayName != null && arrayItem.displayName != undefined && arrayItem.displayName != ''){
								nodeData[key + '_list'].push(arrayItem);
							}
						}
						diagram.model.setDataProperty(nodeData, key, list_value);
						break;
					//  STRY0113883
					case 'photo':
					case 'profile':
						// these are handled in a function b/c they need to post back to the server
						loadUserInfo(field.type, nodeData.key, key, record[key].value, displayValue );
				}
			} //if field wasn't found do nothing
		}

		var name = nodeData.office_name + '\n  (' + nodeData.office_abbreviation + ')';
		diagram.model.setDataProperty(nodeData, 'name', name);

		var ouHAValue = nodeData('u_ou_hierarchy_administrators');
		var isAdmin = (c.data.isGHA || (ouHAValue && ouHAValue.indexOf(c.data.currentUser)>=0));
		diagram.model.setDataProperty(nodeData, 'isAdmin', isAdmin);

		diagram.model.updateTargetBindings(nodeData);
	}

	// STRY0113883 load user profile and/or  Photo information
	function loadUserInfo(fieldType, nodeKey, fieldName, value, displayValue){
		if (fieldType == 'photo') {
			c.data.getPhoto = true;
		} else if (fieldType == 'profile') {
			c.data.getProfile = true;
		}
		c.data.getUserGUID = value;
		c.data.getUserDisplayValue = displayValue;
		c.server.update().then(function(){
			// find the node to update again
			var nodeData = diagram.model.findNodeDataForKey(nodeKey);
			if (nodeData) {
				nodeData[fieldName + '_photoName'] = c.data.updatedPhoto.photoName;
				diagram.model.setDataProperty(nodeData, fieldName + '_photoName', c.data.updatedPhoto.photoName);

				if(c.data.updatedPhoto.photo){
					nodeData[fieldName + '_photo'] = c.data.updatedPhoto.photo;
					diagram.model.setDataProperty(nodeData, fieldName + '_photo', c.data.updatedPhoto.photo);
				}

				if(c.data.updatedProfile){
					newNodeData[fieldName + '_profile'] = c.data.updatedProfile;
					diagram.model.setDataProperty(nodeData, fieldName + '_profile', c.data.updatedProfile);
				}
				diagram.model.updateTargetBindings(nodeData);
			}
		});
	}

	// DFCT0010275
	$scope.openNewModal = function() {
		spModal.open({
			title: 'New Top Organizational Unit',
			backdrop:'static',
			widget: 'discovertasker-formtab',
			widgetInput: {
				table: c.data.table,
				view: 'Simple',
				sys_id: "-1",
				omitHeader: 'true',
				isModal: true //,
			},
			size: 'lg',
			buttons: [],
			// 2.7.2 | 2022-01-13 | mmcc | STRY0110656 - UI- Fixed Header and Button Bars on ALL Modals and lists
			footerStyle: {
				'display': 'none'
			}
		});		
	};

	function broadcastTopNodeChange(topId) {
		var evt = {};
			evt.sys_id = topId;
			evt.table = 'x_153465_discovert_discover_office_hierarchy';
			// RJ -ET - Story 4
			evt.parent = '';
			$rootScope.$broadcast('$sp.list.click', evt);
		}

	// STRY0074597
	$scope.topOnlyCheck = function() {
		setOUPicker();
	};

	// STRY0074597
	function setOUPicker(){
		if(c.data.topOnly){
			c.data.OUPicker_displayFields='office_abbreviation,office_name';
			c.data.OUPicker_searchFields = 'office_abbreviation,office_name';
			c.data.OUPicker_query='active=true^parentISEMPTY';
		}else{
			c.data.OUPicker_displayFields='office_level,office_abbreviation,office_name';
			c.data.OUPicker_searchFields = 'office_level,office_abbreviation,office_name';
			c.data.OUPicker_query='active=true';
		}
	}

	$scope.$on("field.change",function(evt,params){
		c.data.topOU = $scope.topOU.value;
		c.data.selectedId = c.data.topOU;
		c.server.update().then(function(){
			// STRY0116823
			resetDiagram();				
		});
		broadcastTopNodeChange(c.data.selectedId);
	});

	$scope.expandGraph = function(){
		spModal.open({
			title: "",
			backdrop:'static',
			widget: 'discovertasker-officehierarchy',
			// STRY0074597
			widgetInput: {topOU:$scope.topOU.value,
						  topOnly:c.data.topOnly
						 },
			size: 'lg',
			buttons: [],
			// 2.7.2 | 2022-01-13 | mmcc | STRY0110656 - UI- Fixed Header and Button Bars on ALL Modals and lists
			footerStyle: {
				'display': 'none'
			}
		});
	};

	// RJ -ET - Story 4
	// STRY0093948 - the tasker form with tab is rasing this as a rootscope broadcast, updated to catch
	$rootScope.$on('$taskerTabbedForm.drillDownList.click', function(e, parms) {
		// STRY0074663 Only rebroadcast if the node changed
		if(c.data.selectedId != parms.sys_id){
			c.data.selectedId = parms.sys_id;
			// Select the node using the sys_id parameter supplied.
			var node_select = diagram.findNodeForKey(c.data.selectedId);
			diagram.select(node_select);
			diagram.centerRect(node_select.actualBounds);
		}

	});

	function nodeSelectionChanged(node) {
		var evt = {};
		var d = node.data;
		evt.sys_id = d.sys_id;
		if (evt.sys_id == c.data.selectedId)  // get called twice by gojs
			return;

		// STRY0116812
		evt.table = c.data.table; //d.sys_class_name || d.table;
		c.data.selectedId = evt.sys_id;
		// RJ -ET - Story 4
		evt.parent = d.parent;
		c.data.selectedId = evt.sys_id;
		$location.search('table', evt.table).search('sys_id', evt.sys_id).search('spa', 1);
		$rootScope.$broadcast('$sp.list.click', evt);

		diagram.centerRect(node.actualBounds);
	}

	$scope.$on("field.change", function(evt, parms) {
		if (parms.field.name == 'page')
			changePage(parms.newValue);
	});

	function changePage(p){
		var path = $location.path();
		var searchParms = $location.search();
		$location.search({id: searchParms.id, p: p});
	}

