	function hoverGradientPanel() {
		// ************************************************************************
		// NOTE: the block is FULL SCREEN ONLY
		// ************************************************************************
		var gradientPanel =		
				$go(go.Shape, "Rectangle",  // Horizontal panel for Image and Icons
						{opacity: 0.0,
						 name: "gradientRectangle",
						 strokeWidth: 0, 
						 alignment: go.Spot.Right,
						 angle:90,
						 // DFCT0010761 =- changed width (which is hieght at 90 degress from 40 to 60
						 width:60, height:250, // this is ODD, but it is turned at a 90 degree angle for the linear gradient.  So, Height and widht are swapped
						 fill: $go(go.Brush, "Linear", { 0.0: "rgba(51, 115, 142, 1.0)", 0.7: "rgba(51, 115, 142, 1.0)", 1.0: "rgba(51, 115, 142, 0.0)"})},
						// STRY0114110
						new go.Binding("fill", "active", function (t){
					if(t)
						return $go(go.Brush, "Linear", { 0.0: "rgba(51, 115, 142, 1.0)", 0.7: "rgba(51, 115, 142, 1.0)", 1.0: "rgba(51, 115, 142, 0.0)"});
					else
						return $go(go.Brush, "Linear", { 0.0: "rgba(120, 120, 120, 1.0)", 0.7: "rgba(120, 120, 120, 1.0)", 1.0: "rgba(120, 120, 120, 0.0)"});})
					 );
		return gradientPanel;
	}

	function hoverIconPanel(){
		var hoverIcons = 
				$go(go.Panel, "Spot",  // Horizontal panel for Image and Icons
						{name: "Icons",
						 visible: false,
						 alignment: go.Spot.Right},
						$go(go.Panel, "Horizontal", // Horizontal panel that contains the icons, set to top right
								{visible: c.data.settings.isFullScreen,
								alignment: go.Spot.Right, width: 250, isOpposite: true},
								addImage(c.data.icons.GenericAddSub16, c.data.topIconOpacity, '', ''),
								addImage(c.data.icons.Request16, c.data.topIconOpacity, '', ''),
								// STRY0101474

								addImage(c.data.icons.Divider, c.data.topIconOpacity, '', ''),
								// DFCT0010634 - removed for initial release until we know what report to load in the modal
								//addImage(c.data.icons.Reports16, c.data.topIconOpacity, '', ''),
								addImage(c.data.icons.RelatedTasks16, c.data.topIconOpacity, '', ''),
								addImage(c.data.icons.Contacts16, c.data.topIconOpacity, '', ''),
								addImage(c.data.icons.OUMembers16, c.data.topIconOpacity, '', ''),
								addImage(c.data.icons.SubOU16, c.data.topIconOpacity, '', ''),
								addImage(c.data.icons.Information16, c.data.topIconOpacity, '', '')
							 ) // end horizontal panel holding the icons	
					 ); // end horizontal Panel holding Images and icons
		return hoverIcons;
	}

	function createPermissiveCircle() {
		// STRY0114088, STRY0111888 - if permissive show open lock (this graphic has an outter band.  so, don't need the border circle)
		var permissiveCircle =
				$go(go.Shape, "Circle", 
						{ width: TREE_CONST.iconCircleSize, strokeWidth: TREE_CONST.outlineWidth,
						 // STRY0113884
						 alignment: new go.Spot(0, 1, TREE_CONST.leftIconCornerOffset, TREE_CONST.bottomIconCornerOffset) },
						new go.Binding("visible", "u_ou_is_permissive", function (u_ou_is_permissive){
							if(u_ou_is_permissive)
								return c.data.settings.isFullScreen && c.data.settings.permissiveOn;
							else
								return false;}),
						new go.Binding("fill", "active", function (t){
							if(t)
								return TREE_CONST.node_active_bg;
							else
								return TREE_CONST.node_inactive_bg;}),
						// if selected, outline the circle
						new go.Binding("stroke", "", function(node){
							if (node.isSelected)
								return TREE_CONST.node_selected_border; 
							else if(node.data.active)
								return TREE_CONST.node_active_bg;
							else
								return TREE_CONST.node_inactive_bg;}).ofObject("")
					 );
		return permissiveCircle;				
	}

	function createPermissiveIcon(){
		var permissiveIcon = 
				$go(go.Panel, "Spot", // panel to hold the image clipped into a circle
						// STRY0113884
						{alignment: new go.Spot(0, 1, TREE_CONST.leftIconCornerOffset, TREE_CONST.bottomIconCornerOffset)}, 
						new go.Binding("visible", "u_ou_is_permissive", function (u_ou_is_permissive){
							if(u_ou_is_permissive)
								return c.data.settings.isFullScreen && c.data.settings.permissiveOn;
							else
								return false;}),
						addImage(c.data.icons.LockOpenBadge24, TREE_CONST.icon_opacity_normal, '', '')
					 ); // end panel holding circle and unlock icon
		return permissiveIcon;
	}

	function createOutstandingRequestCircle(){
		var outstandingRequestCircle = 
				$go(go.Shape, "Circle", 
						{visible: false,
						 // STRY0114088, STRY0113936
						 width: TREE_CONST.iconCircleSize, strokeWidth: TREE_CONST.outlineWidth, 
						 // STRY0113936
						 alignment: new go.Spot(1, 1, TREE_CONST.rightIconCornerOffset, TREE_CONST.bottomIconCornerOffset)},
						new go.Binding("visible", "", function (data){
							if(data.u_outstanding_request_count && c.data.settings.isFullScreen)
								return data.isAdmin && data.u_outstanding_request_count > 0;
							else
								return false;}),
						new go.Binding("fill", "active", function (t){
							if(t)
								return TREE_CONST.node_active_bg;
							else
								return TREE_CONST.node_inactive_bg;}),
						// if selected, outline the circle
						new go.Binding("stroke", "", function(node){
							if (node.isSelected)
								return TREE_CONST.node_selected_border; 
							else if(node.data.active)
								return TREE_CONST.node_active_bg;
							else
								return TREE_CONST.node_inactive_bg;}).ofObject("")
					 );
		return outstandingRequestCircle;
	}

	function createOutstandingRequestIcon(){
		var outstandingRequestIcon =
				$go(go.Panel, "Spot", // panel to hold the image clipped into a circle
						// STRY0113936
						{alignment: new go.Spot(1, 1, TREE_CONST.rightIconCornerOffset, TREE_CONST.bottomIconCornerOffset)}, 
						new go.Binding("visible", "", function (data){
							if(data.u_outstanding_request_count && c.data.settings.isFullScreen)
								return data.isAdmin && data.u_outstanding_request_count > 0;
							else
								return false;}),
						addImage(c.data.icons.ProcessRequestBadge24, c.data.topIconOpacity, '', '')
					 ); // end panel holding circle and unlock icon		
		return outstandingRequestIcon;
	}

	// 2.8 | 2022-03-04 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel; Start	
	function showPopoverUserInfo(obj, diagram, tool) {

		c.data.isPopoverOpened = true;

		c.data.popoverRecord = obj.part.data.u_ou_primary_contact_profile;
		c.data.popoverRecord.photo = _setStyleBackgroundImage(obj.part.data.u_ou_primary_contact_photo);

		// 2.8 | 2022-03-10 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel
		c.data.popoverRecord.messages = _loadProfileMessages(obj.part.data.office_abbreviation);
		c.data.popoverRecord.icons = _loadProfileIcons();

		// since GoJS's use of HTMLInfo is outside of the AngularJS context, 
		// we use below to have the bindings updated
		$scope.$apply();

		var popoverDiv = angular.element(document.getElementById('popoverWrapper'))[0];

		var pt = diagram.lastInput.viewPoint;
		popoverDiv.style.left = Math.ceil(pt.x) + "px";
		popoverDiv.style.top = Math.ceil(pt.y + 120) + "px";
		popoverDiv.style.display = "block";

		c.popoverTimeout = $timeout(function() {
			c.data.isPopoverOpened = false;
		}, diagram.toolManager.toolTipDuration - 100);
	}

	function hidePopoverUserInfo(diagram, tool) {
		if (c.data.isPopoverOpened == false) {
			var popoverDiv = angular.element(document.getElementById('popoverWrapper'))[0];
			popoverDiv.style.display = "none";
			_resetPopoverObject();
			// since GoJS's use of HTMLInfo is outside of the AngularJS context, 
			// we use below to have the bindings updated
			$scope.$apply();
		}
	}

	c.avatarMouseEnter =  function() {
		c.data.isPopoverOpened = true;
		$timeout.cancel(c.popoverTimeout);
	};

	c.avatarMouseLeave =  function() {
		c.data.isPopoverOpened = false;
		var popoverDiv = angular.element(document.getElementById('popoverWrapper'))[0];
			popoverDiv.style.display = "none";
		_resetPopoverObject();
	};

	function _resetPopoverObject() {
		c.data.popoverRecord = {
			sys_id: '',
			name: '',
			first_name: '',
			last_name: '',
			middle_name: '',
			email: '',
			businessPhone: '',
			mobilePhone: '',
			location: '',
			time_zone: '',
			contactPageHref: '',
			photo: '',
			connectEnabled: '',
			liveProfileId: '',
			userId: '',
			messages: {},
			icons: {}
		};
	}
	// 2.8 | 2022-03-04 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel; end

	// 2.8 | 2022-03-10 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel
	function _loadProfileMessages(abbrev) {
		var tempMessages = {
			emailSubject: c.data.messages['Tasker - Tasker Message: Organizational Unit: '] + abbrev,
			buttonText: c.data.messages['Tasker - Button - Message'],
			row3Message: c.data.messages['Tasker - Open Contact Page']
		};

		return tempMessages;
	}

	// 2.8 | 2022-03-10 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel
	function _loadProfileIcons() {
		var tempIcons = {
			BusinessPhone16: c.data.icons.BusinessPhone16,
			Mail16: c.data.icons.Mail16,
			Phone16: c.data.icons.Phone16
		};

		return tempIcons;
	}

	// 2.8 | 2022-03-10 | mmcc | STRY0114672 - Org Hierarchy Full Screen- Tree Node- Any Members List- Update to Popover Panel
	function showPopoverList(obj, diagram, tool) {
		//debugger;
		//console.log('showPopoverList obj.source: ' + obj.source);

		_resetPopoverListObject();
		c.data.isPopoverListOpened = true;
		c.data.popoverListOptions.isSpinnerShown = true;

		c.data.popoverListRecord.title = c.data.icons.OUMembers16.title;

		// since GoJS's use of HTMLInfo is outside of the AngularJS context, 
		// we use below to have the bindings updated
		$scope.$apply();

		var popoverDiv = angular.element(document.getElementById('popoverWrapperList'))[0];

		var pt = diagram.lastInput.viewPoint;
		popoverDiv.style.left = Math.ceil(pt.x) + 'px';
		popoverDiv.style.top = Math.ceil(pt.y + 110) + 'px';
		popoverDiv.style.display = "block";

		c.popoverListTimeout = $timeout(function() {
			c.data.isPopoverListOpened = false;
			c.data.popoverListOptions.isSpinnerShown = false;
		}, diagram.toolManager.toolTipDuration - 100);

		c.data.ouId = obj.part.data.sys_id;
		c.data.isPersonListNeeded = true;

		c.server.update().then(function() {
			c.data.popoverListRecord.persons = c.data.updatedOUList;
			c.data.popoverListOptions.isSpinnerShown = false;
		});
	}

	// 2.8 | 2022-03-10 | mmcc | STRY0114672 - Org Hierarchy Full Screen- Tree Node- Any Members List- Update to Popover Panel
	function hidePopoverList(diagram, tool) {
		if (c.data.isPopoverListOpened == false) {
			var popoverDiv = angular.element(document.getElementById('popoverWrapperList'))[0];
			popoverDiv.style.display = "none";

			_resetPopoverListObject();

			// since GoJS's use of HTMLInfo is outside of the AngularJS context, 
			// we use below to have the bindings updated
			$scope.$apply();
		}	
	}

	c.listMouseEnter =  function() {
		c.data.isPopoverListOpened = true;
		$timeout.cancel(c.popoverListTimeout);
	};

	c.listMouseLeave =  function() {
		c.data.isPopoverListOpened = false;
		var popoverDiv = angular.element(document.getElementById('popoverWrapperList'))[0];
			popoverDiv.style.display = "none";
		_resetPopoverListObject();
	};

	// 2.8 | 2022-03-10 | mmcc | STRY0114672 - Org Hierarchy Full Screen- Tree Node- Any Members List- Update to Popover Panel
	function _resetPopoverListObject() {
		c.data.popoverListRecord = {
			sys_id: '',
			name: '',
			contactPageHref: '',
			photo: '',
			title: ''
		};
	}

	// Returns a string to set a style tag over in the HTML to  display a persons' photo
	// Parameter photo is sys_user avatar field with .iix?t=small appended
	function  _setStyleBackgroundImage(photo) {
		var imageUrl = '';

		if (photo != undefined) {
			imageUrl = "background-image: url('" + photo + "');";
		} else {
			imageUrl = "background-image: url('Profile16.svg');";
		}

		return imageUrl;
	}
};

