// Copyrights belong to Discover Technologies LLC. © 2021 Discover Technologies LLC
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES & BRIAN KEENER
// GRAPHICAL TREE FOR PROCESS DEFINITION
//------------------------------------------------------------------------------------------------------------------------
//
// 2.7.0 | 2021-08-22 | raj | STRY0108231 - DIA- Visual Indicators for Organizational Hierarchy Admins- Fix Script
//                                          Changes in Server script, Client Script, HTML
// 2.7.0 | 2021-09-18 | raj | STRY0101474 - Stretch- Add Create Subtask Button to Task Tree View, Template Tree View
//																				Changes in Server script and Client Script
// 2.7.0 | 2021-10-04 | raj | STRY0105791 - Simple Task Forms- Placeholder Story
//																				Changes in Server script and Client Script
// 2.7.0 | 2021-10-07 | raj | DFCT0010565 - Most of the Modals on Tasker are broken
//																				Changes in Server script
// 2.7.0 | 2021-10-15 | raj | DFCT0010560 - Adding Sub OU with OUHA - Blank record and "Read-Only" fields on modal
//																				Changes in Client script
// 2.7.0 | 2021-10-15 | raj | STRY0111888 - added permissinve graphics and updated profile picture
//																				Changes in Server script and Client Script
// 2.7.0 | 2021-10-20 | raj | STRY0112710 - HHS- Strong Matrix- Permissive OU Tasking- Visual Indicators- Tooltips
//                            STRY0111072 - Organizational Hierarchy Full-screen–- OU Management Icons- Add Tooltips  
//                            STRY0111076 - Organizational Hierarchy Full-screen– Adjust Ordering of Icons- Related Tasks Icon  
//																				Changes in Server script and Client Script
// 2.7.0 | 2021-10-24 | raj  | DFCT0010594 - "Organizational Hierarchy in full-screen view" displays an empty modal
//                                         Changes made in HTML
// 2.7.0 | 2021-10-27 | raj  | STRY0113084 - Templates- Duration Fields- Update Label and Info Text
//                                         Changes made in Client Script and Server Script
// 2.7.0 | 2021-11-01 | raj  | DFCT0010620 - Body & Subject Incorrect: Response for OU Request Email is going to ${Responder} NOT ${Requestor} , URL for Order By was not right.
//                                         Changes made in Client Script
// 2.7.0 | 2021-11-01 | raj  | DFCT0010634 - "Report" icon is displaying in Full Screen view
//                                         Changes made in Client Script
// 2.7.0 | 2021-11-01 | raj  | STRY0114110 - Org Hierarchy Full Screen- Tree Node- Hover-panel "Style Update" for Inactive OUs
//                                         Changes made in Client Script
// 2.7.0 | 2021-11-11 | raj  | STRY0113881 - Org Hierarchy Full Screen- Tree Node- "Process Request" Indicator
//                                         Changes made in Server Script
// 2.7.0 | 2021-12-06 | raj  | STRY0113936 - Org Hierarchy Full Screen- Tree Node- "Process Request" Indicator- Styling & Popover Update
//														 STRY0114088 - Org Hierarchy Full Screen- Tree Node- Highlight Styling
//														 STRY0113884 - Org Hierarchy Full Screen- Tree Node- Permissive Tasking Indicator Styling
//                                         Changes made in Client Controller
// 2.7.101 | 2021-12-26 | raj  | STRY0116017 - Org Hierarchy Fullscreen- Member List Modal- Service Portal view as default
//										Changes in Client controller only - comment added in a nother update set
// 2.7.101 | 2022-01-04 | raj  | DFCT0010275 - New Tasker Setup - Not able to create initial/parent OU
//										Changes in Server, Client controller and HTML
// 2.7.2 | 2022-01-06 | raj  | STRY0115843 - Org Hierarchy Fullscreen- OU Information Modal- Match information displayed on split-view
//										Changes Client controller
// 2.7.0 | 2021-11-01 | raj  | DFCT0010634 - "Report" icon is displaying in Full Screen view
//                                      Changes made in Client Script
// 2.7.2 | 2022-01-13 | mmcc | STRY0110656 - UI- Fixed Header and Button Bars on ALL Modals and lists
//                                      In Client controller, added code for footerstyle display none; added missing semicolons
//                                      Changes made in Client controller
// 2.8 | 2022-01-19 | raj  | STRY0116812 - TECH - Update Org Tree to handle record watcher the same way Task and Template do (no diagram redraw)
//                                      Changes made in Server Script and Client controller
// 2.8 | 2022-01-19 | raj  | STRY0113679 - Org Hierarchy Tree- Update Fullscreen Icon to open in current tab
//                                      Changes made in Server Script and HTML
// 2.8 | 2022-01-25 | raj  | STRY0116822 - Org Hierarchy Tree- Bifold Widget and Fullscreen view- Fit to screen and internally scrollable
//                                      Changes made in Server Client controller and HTML
// 2.8 | 2022-01-25 | raj  | STRY0116823 - Org Hierarchy Tree- Bifold Widget and Fullscreen view- Add Picture-in-picture feature
//                                      Changes made in Server Client controller and HTML and CSS
// 2.8 | 2022-02-19 | raj  | DFCT0010796 - Tooltip is incorrect on the Org Hier. "Maximize" and  "Minimize " iconsDFCT0010796
//                                      Changes made in Server
// 2.8 | 2022-02-19 | raj  | DFCT0010796 - Tooltip is incorrect on the Org Hier. "Maximize" and  "Minimize " iconsDFCT0010796
//                                      Changes made in Server
// 2.8 | 2022-02-28 | raj  | STRY0113883 - Org Hierarchy Full Screen- Tree Node- Avatar Control Indicator 
//                                      Changes made in Server and Client Script
// 2.8 | 2022-03-04 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel
//                                      In HTML, added a div id="popoverWrapper" to wrap the Element Directive
//                                      In Server script, initialize popoverRecord variable 
//                                      In Client controller, set .hoverDelay = 700; add several functions
//                                      Changes made in HTML, Server script and Client controller
//                                      2022-03-10 Renamed directive dtechGraphObjectPopover to the new name dtechPopoverProfile
// 2.8 | 2022-03-06 | raj  | TECH - Update reorganize client code that builds the tree to improve readability
//                                      Changes made in Client controller
// 2.8 | 2022-03-10 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel
//                                      In Client controller, use message key 'Tasker - Open Contact Page'; use messages object
//                                      Added _loadProfileMessages() and _loadProfileIcons();
//                                      Changes made in Client controller
// 2.8 | 2022-03-10 | mmcc | STRY0114672 - Org Hierarchy Full Screen- Tree Node- Any Members List- Update to Popover Panel
//                                      In HTML, added <div id="popoverWrapperList"
//                                      In Server script, added initialize for popoverListRecord
//                                      In Client controller, added showPopoverList()
//                                      Changes made in HTML, Server and Client
// 2.8 | 2022-03-12 | raj  | TECH - Update reorganize client code that builds the tree to improve readability
//                                      created main function and organized constants and variables
//                                      Changes made in Client controller
// 2.8 | 2022-03-13 | raj  | STRY0117949 - Org Hierarchy Bifold- Revamp- Tree Widget Header Update
//                                      Changes made in Client controller and HTML
// 2.8 | 2022-03-13 | raj  | DFCT0010813 - Organizational Hierarchy on new install displays incorrectly/missing icons/buttons
//                                      Changes made in Server Script
//------------------------------------------------------------------------------------------------------------------------

(function($sp, input, data, options, gs) {

	//  STRY0113883 - reworked code flow
	main();

	function main() {
		// if messages not loaded, load messages
		var taskWidgetIconsAndMessage = new TaskerWidgetIconsAndMessages('discovertasker-officehierarchy');

		if(input){
			// save percent change and return
			if(input.percentChanged){
				taskWidgetIconsAndMessage.savePreferencePercent(input.settings.selectPercent);
				return;
			}
			if(input.favoriteChanged){
				taskWidgetIconsAndMessage.savePreferenceFavorite(input.settings.favorite);
				return;
			}
			if(input.topOU){
				loadOUmap(input.topOU,input.topOU);
				return;
			}
			//  STRY0113883
			if(input.getPhoto){
				data.updatedPhoto = loadPhoto(input.getUserDisplayValue, input.getUserGUID);
			}
			//  STRY0113883
			if(input.getProfile){
				data.updatedPhoto = loadPhoto(input.getUserDisplayValue, input.getUserGUID);
				data.updatedProfile = loadProfile(input.getUserGUID);
			}

			// 2.8 | 2022-03-10 | mmcc | STRY0114672 - Org Hierarchy Full Screen- Tree Node- Any Members List- Update to Popover Panel
			if(input.isPersonListNeeded) {
				data.updatedOUList = [];
				//can this be global, at top of main()
				var taskWidgetData = new TaskWidgetData();
				data.updatedOUList = taskWidgetData.getHoverMembersArray(input.ouId);
			}
		} else {
			// DFCT0010813
			data.table = 'x_153465_discovert_discover_office_hierarchy';
			data.map = [];

			// 2.8 | 2022-03-04 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel; init as an empty object
			data.popoverRecord = {};

			// 2.8 | 2022-03-10 | mmcc | STRY0114672 - Org Hierarchy Full Screen- Tree Node- Any Members List- Update to Popover Panel
			data.popoverListRecord = {};
			data.popoverListOptions = {
				isSpinnerShown: false,
				maxRowsToDisplay: 5
			};

			data.settings = taskWidgetIconsAndMessage.loadDefaultsAndSettings($sp);
			data.currentUser = gs.getUserID();

			data.messages = taskWidgetIconsAndMessage.loadMessages();
			data.icons = taskWidgetIconsAndMessage.loadIcons();

			// STRY0101474  - DFCT0010275
			data.isGHA = new	UserInfoScripts().UserHasRole('x_153465_discovert.tasker_organizational_admin');

			// DFCT0010813 - moved down to load messages and icons
			// if there is no top OU, then stop
			if (data.settings.topParentNeeded) {
				return;
			}

			var selectedId = setSelected();

			loadOUmap(selectedId, undefined);			
		}
	}

	//  STRY0113883
	function loadProfile(userGUID){
		var taskWidgetData = new TaskWidgetData();
		return taskWidgetData.loadProfileInfo(userGUID);		
	}
	//  STRY0113883
	function loadPhoto(displayValue, userGUID){
		var taskWidgetData = new TaskWidgetData();
		return taskWidgetData.loadPhotoInfo(displayValue, userGUID);
	}

	function loadOUmap(selectedId, topOU){
		// DFCT0010813
		var map = data.map;

		data.selectedId = selectedId;

		var gr_ou = getTopOUgr(data.selectedId, topOU);
		data.currentTopOU = gr_ou.getUniqueValue();

		if (!data.currentTopOU  || data.currentTopOU == '') {
			data.currentTopOU = null;
			return;
		}

		data.title = gr_ou.getValue('office_abbreviation');
		data.office_name = gr_ou.getValue('office_name');

		var taskWidgetData = new TaskWidgetData();
		data.fieldsInModel = taskWidgetData.loadOfficeTreeFieldsAndFieldLabels(gr_ou);

		taskWidgetData.buildOUMap('discovertasker-officehierarchy', map, gr_ou, data.fieldsInModel);

	}

	function setSelected(){
		var selectedId;

		if($sp.getParameter("sys_id")){
			// set the default selected id from the url
			selectedId = $sp.getParameter("sys_id");						
		} else if(data.settings.favorite.value != ''){
			selectedId = data.settings.favorite.value;
		} else if (data.settings.defaultOU.value != ''){
			// do not override the URL or the favorite on load
			selectedId = data.settings.defaultOU.value;
		}
		return selectedId;

	}

	function getTopOUgr (selectedId, topOU){
		var currentTopOU;
		if(topOU){
			currentTopOU = topOU;
		} else {
			var orgScripts = new OrganizationalScripts();
			currentTopOU = orgScripts.getTopOUId(selectedId);
		}
		// RJ -ET - Story 4
		var gr_TopOU = new GlideRecordSecure(data.table);

		if (!gr_TopOU.get(currentTopOU)) {
			// if the glide record isn't found, rather than returning no tree
			// find the first top OU and load the tree for it
			gr_TopOU.addNullQuery('parent');
			gr_TopOU.query();
			gr_TopOU.next();	
		}
		return gr_TopOU;
	}
})($sp, input, data, options, gs);
